import{_ as i,o as e,c as l,a3 as t}from"./chunks/framework.gsMzR_Kb.js";const p=JSON.parse('{"title":"刚柔","description":"阴阳进一步落到性情、力度与处事趋向时，常会展开成刚柔。","frontmatter":{"title":"刚柔","description":"阴阳进一步落到性情、力度与处事趋向时，常会展开成刚柔。","category":"concept","aliases":["刚柔","易经刚柔","gang rou"]},"headers":[],"relativePath":"yijing/basics/concepts/gang-rou.md","filePath":"yijing/basics/concepts/gang-rou.md","lastUpdated":1777132262000}'),o={name:"yijing/basics/concepts/gang-rou.md"};function r(n,a,s,c,h,d){return e(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="刚柔" tabindex="-1">刚柔 <a class="header-anchor" href="#刚柔" aria-label="Permalink to &quot;刚柔&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>刚柔可以先理解为阴阳进一步落在具体表现上的两种倾向。</p><ul><li>刚，更偏主动、坚决、外发、能担当</li><li>柔，更偏承接、调和、含容、能顺应</li></ul><p>它们不是道德标签，也不是“刚一定高于柔”。《易》更关心的，是某一处境下刚柔是否得宜。</p><h2 id="常见误解" tabindex="-1">常见误解 <a class="header-anchor" href="#常见误解" aria-label="Permalink to &quot;常见误解&quot;">​</a></h2><ul><li>把刚读成永远正确，把柔读成永远退让</li><li>把刚柔只读成性格词，而忽略它在卦爻关系中的判断意义</li><li>以为刚柔只讲男女、强弱，而忽略它与时位相配的问题</li></ul><p>《易》的重点从来不是只问“你刚还是柔”，而是问“你在这个位置、这个时势里，刚柔是否相称”。</p><h2 id="在原典中的语境" tabindex="-1">在原典中的语境 <a class="header-anchor" href="#在原典中的语境" aria-label="Permalink to &quot;在原典中的语境&quot;">​</a></h2><ul><li>卦爻系统中，阳爻常被视作刚，阴爻常被视作柔，但具体吉凶还要结合时位来看。</li><li>《文言》《彖传》里常会出现刚柔相推、刚柔得中等表述，说明刚柔要放在关系中看。</li><li>许多卦的意义变化，也正来自刚柔配置不同。</li></ul><h2 id="我的理解" tabindex="-1">我的理解 <a class="header-anchor" href="#我的理解" aria-label="Permalink to &quot;我的理解&quot;">​</a></h2><p>待补：后续可结合乾、坤、泰、否等卦，继续补自己对“刚柔得宜”与“刚柔失配”的感受。</p><h2 id="关联页面" tabindex="-1">关联页面 <a class="header-anchor" href="#关联页面" aria-label="Permalink to &quot;关联页面&quot;">​</a></h2><ul><li><a href="/Dao/yijing/basics/concepts/yin-yang">阴阳</a></li><li><a href="/Dao/yijing/basics/concepts/zhong-zheng">中正</a></li><li><a href="/Dao/yijing/basics/concepts/wei">位</a></li><li><a href="/Dao/yijing/basics/concepts/shi">时</a></li></ul><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>《周易》</li><li>《彖传》</li><li>《文言传》</li></ul>',16)])])}const g=i(o,[["render",r]]);export{p as __pageData,g as default};
